def freq_response(b, a):
    w, h = signal.freqz(b, a, worN=NFFT)
    freq_hz = w / np.pi * (FS / 2)
    mag_db  = 20 * np.log10(np.abs(h) + 1e-12)
    phase   = np.unwrap(np.angle(h)) * 180 / np.pi
    return freq_hz, mag_db, phase

