def update_pole_zero(b, a):
    z, p, _ = signal.tf2zpk(b, a)
    zeros_plot.set_data(z.real, z.imag)
    poles_plot.set_data(p.real, p.imag)
    margin = 0.3
    all_pts = np.concatenate([z, p, [1+0j, -1+0j, 1j, -1j]])
    lim = max(np.abs(all_pts).max() + margin, 1.4)
    ax_pole.set_xlim(-lim, lim)
    ax_pole.set_ylim(-lim, lim)

